import React, { useState, useEffect } from 'react';
import './LiveUsers.css';

const LiveUsers: React.FC = () => {
  const [liveCount, setLiveCount] = useState(1247);
  const [chartData] = useState([
    { time: '00:00', users: 850 },
    { time: '04:00', users: 720 },
    { time: '08:00', users: 1100 },
    { time: '12:00', users: 1350 },
    { time: '16:00', users: 1200 },
    { time: '20:00', users: 1247 },
  ]);

  // Simulate real-time updates
  useEffect(() => {
    const interval = setInterval(() => {
      const variation = Math.floor(Math.random() * 50) - 25;
      setLiveCount(prev => Math.max(1000, prev + variation));
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  const maxUsers = Math.max(...chartData.map(d => d.users));
  const minUsers = Math.min(...chartData.map(d => d.users));

  return (
    <div className="live-users-card">
      <div className="live-users-header">
        <div className="header-left">
          <h2>Live Users</h2>
          <div className="live-indicator">
            <div className="live-dot"></div>
            <span>Live</span>
          </div>
        </div>
        <div className="live-count">
          <span className="count-number">{liveCount.toLocaleString()}</span>
          <span className="count-label">Active Users</span>
        </div>
      </div>

      <div className="chart-section">
        <div className="simple-chart">
          {chartData.map((point, index) => {
            const height = ((point.users - minUsers) / (maxUsers - minUsers)) * 100;
            return (
              <div key={index} className="chart-bar">
                <div 
                  className="bar-fill" 
                  style={{ height: `${height}%` }}
                  title={`${point.time}: ${point.users} users`}
                ></div>
                <span className="bar-label">{point.time}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div className="stats-row">
        <div className="stat-item">
          <span className="stat-value">{maxUsers.toLocaleString()}</span>
          <span className="stat-label">Peak Today</span>
        </div>
        <div className="stat-item">
          <span className="stat-value">{Math.round(chartData.reduce((sum, d) => sum + d.users, 0) / chartData.length).toLocaleString()}</span>
          <span className="stat-label">Average</span>
        </div>
        <div className="stat-item">
          <span className="stat-value">{minUsers.toLocaleString()}</span>
          <span className="stat-label">Low Today</span>
        </div>
      </div>
    </div>
  );
};

export default LiveUsers;
